VALUES
  ('police-f3743df6-moex-00270', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '行政訴訟法第10條規定，選舉罷免事件之爭議，除法律別有規定外，得依本法提起行政訴訟。 請問有關此一條文之解釋，下列何者正確？', '["所謂法律別有規定，係指公職人員選舉罷免法、總統副總統選舉罷免法而言", "選舉無效之訴得依行政訴訟法提起行政訴訟", "當選無效之訴得依行政訴訟法提起行政訴訟", "依行政訴訟法提起之選舉罷免訴訟，其訴訟類型不以撤銷訴訟、確認訴訟及給付訴訟為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00271', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '土地法第68條第1項規定：「因登記錯誤遺漏或虛偽致受損害者，由該地政機關負損害賠償責 任。但該地政機關證明其原因應歸責於受害人時，不在此限」。有關此一條文之解釋，下列何者 錯誤？', '["該條規定為國家賠償法之補充規定，關於國家賠償的要件自應優先適用國家賠償法", "該規定文義既未明示以登記人員之故意或過失為要件，原則上自應由地政機關就登記不實之結 果，負無過失之賠償責任", "除非該地政機關能證明其原因應歸責於受害人，否則即應負損害賠償責任", "該不實登記是否因受害人以外之第三人行為所致，皆不影響該條規定之適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00272', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '依行政程序法之規定，下列何者非屬書面之行政處分得不記明理由之情形？', '["處分相對人無待處分機關之說明已知悉作成處分之理由者", "一般處分經公告或刊登政府公報或新聞紙者", "有關專門知識、技能或資格所為之考試、檢定或鑑定等程序", "行政處分所根據之事實，客觀上明白足以確認者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00273', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '依最高行政法院裁判見解，人民如依政府資訊公開法請求政府機關提供政府資訊遭拒，而欲循序 提起行政訴訟以資救濟，應提起何種類型之行政訴訟？', '["撤銷訴訟", "確認訴訟", "一般給付訴訟", "課予義務訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00274', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', 'A所有之土地被徵收，其對徵收補償價額不服，依土地徵收條例第22條第2項規定以書面提出 異議，經主管機關為維持原補償價額之查處，A對於該查處結果如有不服，應提起何種類型之行 政訴訟以資救濟？', '["撤銷訴訟", "課予義務訴訟", "確認訴訟", "一般給付訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00275', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '依最高行政法院及司法院大法官解釋，下列何者非屬行政契約？', '["公路監理機關與汽車修理業所締結之委託辦理汽車定期檢驗合約書", "退除役軍職人員與臺灣銀行所訂立之優惠存款契約", "中央健康保險署與醫事服務機構所締結之全民健康保險特約醫事服務機構合約", "地方主管機關與都市計畫區域內人民所締結之都市計畫回饋措施協議書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00276', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '依行政罰法之規定，關於行政罰裁處程序之敘述，下列何者正確？', '["扣留物於案件終結前無留存之必要者，原則上應毀棄之", "物之所有人對於扣留不服者，得向扣留機關之上級機關聲明異議", "行政機關所為之裁處，係根據客觀上明白且足以確認之事實者，仍應給予受處罰者陳述意見之 機會", "行政機關為命令歇業之裁罰性不利處分前，原則上應依受處罰者之申請，舉行聽證"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00277', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '依最高行政法院庭長法官聯席會議決議之見解，下列何者為行政處分？', '["公立高中以下學校或主管機關對所屬（轄）教師所為之年終成績考核或平時考核獎懲", "人民團體職員異動，而依人民團體法第54條規定將職員簡歷冊報請主管機關核備，主管機關 所為核備之行為", "公寓大廈管理委員會成立後依公寓大廈管理條例及相關子法規定向主管機關報備，主管機關所 為同意報備之行為", "檢舉人以第三人違反公平交易法規定而向公平交易委員會檢舉，該會對檢舉人所為「檢舉不成 立」之函文"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00278', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '依行政執行法之規定，關於行政執行程序，下列何者錯誤？', '["行政執行原則上不得於夜間為之；但日間已開始執行者，得繼續至夜間", "執行時有遭遇抗拒之虞者，執行機關得於必要時請求其他機關協助執行", "公法上金錢給付義務人經合法通知而無正當理由不到場，其滯欠金額合計新臺幣5萬元，且已 出境三次者，得限制住居", "拘提、管收之聲請，應向行政執行分署所在地之地方行政法院為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00279', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '依行政執行法之規定，下列何者非屬直接強制方法？', '["收繳、註銷證照", "斷絕營業所必須之自來水", "封閉建築物", "對於人之管束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL)
